use std::collections::VecDeque;
use std::sync::{Arc, Mutex};

#[derive(Default)]
struct PoolState {
    pending: usize,
    completed: u64,
}

#[derive(Clone)]
pub struct WorkerPool {
    state: Arc<Mutex<PoolState>>,
}

impl WorkerPool {
    pub fn new() -> Self {
        Self { state: Arc::new(Mutex::new(PoolState::default())) }
    }

    pub fn enqueue(&self, count: usize) {
        let mut guard = self.state.lock().unwrap();
        guard.pending += count;
    }

    pub fn snapshot(&self) -> (usize, u64) {
        let guard = self.state.lock().unwrap();
        (guard.pending, guard.completed)
    }

    pub async fn flush_batch<F>(&self, sink: F) -> usize
    where
        F: Fn(usize) -> futures::future::BoxFuture<'static, ()>,
    {
        let pending = {
            let guard = self.state.lock().unwrap();
            guard.pending
        };
        sink(pending).await;
        pending
    }

    pub async fn record_result<F>(&self, persist: F)
    where
        F: Fn(u64) -> futures::future::BoxFuture<'static, ()>,
    {
        let completed = {
            let mut guard = self.state.lock().unwrap();
            guard.pending = guard.pending.saturating_sub(1);
            guard.completed += 1;
            guard.completed
        };
        persist(completed).await;
    }
}
